import { getFeatureSettings, onBreachDOMContentLoaded } from '@/content-scripts/content-breach-notification/utils';
//@ts-ignore
const useLogging = (ENVIRONMENT == "development");

export async function startCheck() {
    const settings = await getFeatureSettings();
    if (settings?.featureFlag) {
        useLogging && console.debug("DFP: Breach notification feature flag is enabled.", settings.featureFlag);
        if (settings.userSetting) {
            // if both feature flag and user setting are enabled, then show the breach notification
            onBreachDOMContentLoaded();
        } else {
            useLogging && console.debug("DFP: Breach notification user setting is disabled. Skipping breach notification.");
        }
    } else {
        useLogging && console.debug("DFP: Breach notification feature flag is disabled. Skipping breach notification.");
    }
}

// start the check on
document.addEventListener("DOMContentLoaded", startCheck);