
export type EasyListItems = {
    ids: string[] | Set<string>;
    classes: string[] | Set<string>;
    tags: string[] | Set<string>;
    selectors: string[];
    exception_rules: string[];
    specific_hide: string[];
    extended_hide: string[];
    clickables: string[];
};

export type EasyListElement = {
    tabId: number;
    easylist: EasyListItems;
    easylistprivacy: EasyListItems;
    visual_debugging: boolean;
};

export function createEmptyEasyListElements(tabId: number): EasyListElement {
    return {
        tabId,
        easylist: {
            ids: new Set(),
            classes: new Set(),
            tags: new Set(),
            selectors: [],
            exception_rules: [],
            specific_hide: [],
            extended_hide: [],
            clickables: [],
        },
        easylistprivacy: {
            ids: new Set(),
            classes: new Set(),
            tags: new Set(),
            selectors: [],
            exception_rules: [],
            specific_hide: [],
            extended_hide: [],
            clickables: [],
        },
        visual_debugging: false,
    };
}