import { chrome } from '@/utils/polyfill';
import {
    MSG_CHECK_DOMAIN_ALLOW_LIST_RESPONSE,
    MSG_CHECK_ALLOW_LIST_BY_TYPE_AND_DOMAIN,
    MSG_SHELL_INJECTION_CLIPBOARD,
    MSG_ADD_ALLOW,
} from "@/app/scripts/app-consts.js"
import { displayShellInjectionNotification } from '../content-notifications';
import { urlHost } from '@/utils/utils';

const isLoggingEnabled = (): boolean => {
    //@ts-ignore
    return (typeof ENVIRONMENT !== 'undefined' && ENVIRONMENT == "development");
};

export const checkAllowListByTypeAndDomain = (data: any): void => {
    const domainUrl = data.domainUrl;
    const type = data.exclusionType;
    if (!domainUrl || !type) {
        isLoggingEnabled() && console.debug("Content Script Bridge: Invalid data received:", data);
        return;
    } else {
        // Send message to background/service worker
        chrome.runtime.sendMessage(
            {
                type: MSG_CHECK_ALLOW_LIST_BY_TYPE_AND_DOMAIN,
                payload: {
                    type,
                    domainUrl,
                },
            },
            (response) => {
                // Send response back to page context
                isLoggingEnabled() && console.debug("Content Script Bridge: Sending response back to page context:", response);
                window.postMessage(
                    {
                        type: MSG_CHECK_DOMAIN_ALLOW_LIST_RESPONSE,
                        isAllowListed: response?.isAllowListed || false,
                        isProtectionEnabled: response?.isProtectionEnabled || false,
                        isScamsProtectionEnabled: response?.isScamsProtectionEnabled || false
                    },
                    "*"
                );
            }
        );
    }
}

type AllowScamResponse = {
  success?: boolean;
  error?: string;
  excluded?: boolean;
};

export class ShellProtectorBridge {
  static init(): void {
    // Listen for events from the main world content script
    
    // Handle allow scams request
    window.addEventListener('mbg-allow-scams-on-site', async (event: Event) => {
      if (!event.isTrusted) return;
      // Validate that the event is of the expected type and from a trusted source
      if (!(event instanceof CustomEvent)) {
        isLoggingEnabled() && console.warn("BRIDGE: Ignoring mbg-allow-scams-on-site event: not a CustomEvent", event);
        return;
      }

      try {
        const response = await allowScamsOnThisSite();

        // Optionally send response back to main world
        const responseEvent = new CustomEvent('mbg-allow-scams-response', {
          detail: {
            success: !!response,
            error: undefined,
          } as AllowScamResponse,
        });
        window.dispatchEvent(responseEvent);

        isLoggingEnabled() && console.debug("BRIDGE: Allow scams request processed", response);
      } catch (error) {
        isLoggingEnabled() && console.error("BRIDGE: Failed to process allow scams request", error);

        // Send error response back to main world
        const responseEvent = new CustomEvent('mbg-allow-scams-response', {
          detail: {
            success: false,
            error: error instanceof Error ? error.message : String(error),
          } as AllowScamResponse,
        });
        window.dispatchEvent(responseEvent);
      }
    });
    // Handle exclusion check request
    window.addEventListener('mbg-check-exclusion', async (event: Event) => {
      if (!event.isTrusted) return;
      const customEvent = event as CustomEvent;
      try {
        const response = await new Promise<AllowScamResponse>((resolve) => {
          chrome.runtime.sendMessage(
            {
              type: "isExcluded",
              parameters: { type: customEvent.detail.type, url: customEvent.detail.url },
            },
            (response: AllowScamResponse) => {
              resolve(response || {});
            }
          );
        });

        // Send response back to main world
        const responseEvent = new CustomEvent('mbg-exclusion-response', {
          detail: { excluded: !!response?.excluded }
        });
        window.dispatchEvent(responseEvent);
      } catch (error) {
        isLoggingEnabled() && console.error("BRIDGE: Failed to check exclusion", error);
        // Send error response
        const responseEvent = new CustomEvent('mbg-exclusion-response', {
          detail: { excluded: false }
        });
        window.dispatchEvent(responseEvent);
      }
    });

    isLoggingEnabled() && console.debug("BRIDGE: Shell protector bridge initialized");
  }
}

window.addEventListener("message", (event: MessageEvent) => {

  // Only accept messages from the same window
  if (event.source !== window) return;

  const msg = event?.data?.type;

  switch (msg) {
    case MSG_SHELL_INJECTION_CLIPBOARD:
      handleShellInjectionClipboard();
      break;
    default:
      isLoggingEnabled() && msg && console.debug("Content Script Bridge: Unknown message type, ", msg);
      break;
  }
});


function allowScamsOnThisSite(): Promise<boolean> {
    return new Promise((resolve, reject) => {
        chrome.runtime.sendMessage(
            {
                type: MSG_ADD_ALLOW,
                payload: {
                    host: urlHost(window.location.href),
                },
            },
            function (response) {
                if (!response || response.error) {
                    reject(response ? response.error : null);
                } else {
                    resolve(response.success);
                }
            }
        );
    });
}

function dialogEventsHandler(dom: Document | ShadowRoot): void {
    isLoggingEnabled() && console.debug("Attaching events");
    const shellWarningButton = dom.getElementById("mb-disable-shell-warning");
    shellWarningButton?.addEventListener(
        "click",
        async () => {
            try {
                isLoggingEnabled() && console.log("Disabling shell injection warnings for this site");
                await allowScamsOnThisSite();
                const rootElement = document.getElementById("malwarebytes-root");
                rootElement?.remove();
            } catch (error) {
                console.error("CONTENT_SHELL: allowScamsOnThisSite failure", error);
            }
        }
    );
}

export const handleShellInjectionClipboard = (): void => {
    chrome.runtime.sendMessage(
        {
          type: "isExcluded",
          parameters: { type: "scam", url: window.location.href },
        },
        (response) => {
            // Send response back to page context
            isLoggingEnabled() && console.debug("Content Script Bridge: Determine if we should show the notification", response);
            const excluded = !!response?.excluded;
            if (!excluded) {
                isLoggingEnabled() && console.debug("Content Script Bridge: Showing shell injection notification");
                // Display clipboard shell injection notification
                displayShellInjectionNotification(dialogEventsHandler)
            }
        }
    );
}


// Initialize the bridge
ShellProtectorBridge.init();
