//@ts-ignore
const useLogging = (ENVIRONMENT == "development");



export function bypassAdPlayback() {
    const adVideo = document.getElementsByClassName("ad-showing")[0] ||
        document.querySelector(".ytp-ad-text.ytp-ad-preview-text") ||
        document.querySelector("ytp-ad-preview-container");
    const video = document.querySelector("video");
    if (adVideo != undefined && video != undefined) {
        useLogging && console.log("Skipping to the end of the video", adVideo);
        // eslint-disable-next-line max-len
        video.src = "data:video/mp4;base64,";
        if (video.paused) {
            video.play();
        }
    }
}

const youtubeAdTags = [
    {"tag": "ytd-rich-item-renderer ytd-ad-slot-renderer", "remove": true, "refresh": false, "parentLevel": 2},
    {"tag": ".ytd-ad-slot-renderer", "remove": true, "refresh": false},
    {"tag": "tp-yt-iron-overlay-backdrop", "remove": true, "refresh": false,
        "addClasses": ["opened"],
        "removeClasses": ["closed"],
    },
    {"tag": "#movie_player", "remove": false, "refresh": false,
        "addClasses": ["ad-created", "playing-mode"],
        "removeClasses": [
            "ad-interrupting",
            "ytp-hide-controls",
            "ytp-ad-display-override",
            "ended-mode",
            "unstarted-mode",
            "paused-mode",
        ]},
];

export function processYoutubeAds() {

    for (const ad of youtubeAdTags) {
        let elements = document.querySelectorAll(ad.tag);
        if (elements.length === 0) {
            continue;
        }
        if (ad.remove) {
            useLogging && console.log("Removing: ", ad.tag);
            elements.forEach((e) =>  {
                if (ad.parentLevel) {
                    let backCount = ad.parentLevel || 1;
                    while (backCount > 0) {
                        e = e.parentNode;
                        backCount--;
                    }
                }
                e.remove();
            });
        }
        if (ad.removeClasses) {
            elements.forEach((e) => e.classList.remove(...ad.removeClasses));
        }
        if (ad.addClasses) {
            elements.forEach((e) => e.classList.add(...ad.addClasses));
        }
        if (ad.refresh) {
            useLogging && console.log("Refreshing: ", ad.tag);
            window.location.reload();
        }
    }
    bypassAdPlayback();
}
